 1	import { FlexItem, Text, TextVariants, Tooltip } from '@patternfly/react-core';
 2	import { ExclamationTriangleIcon, GlobeAmericasIcon } from '@patternfly/react-icons';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { Warning } from '../../model/warnings';
 6	import { formatDurationAboveMillisecond } from '../../utils/duration';
 7	import './query-summary.css';
 8	
 9	export interface StatsQuerySummaryProps {
10	  detailed?: boolean;
11	  loading?: boolean;
12	  lastRefresh?: Date;
13	  lastDuration?: number;
14	  warning?: Warning;
15	  numQueries?: number;
16	  dataSources?: string[];
17	}
18	
19	export const StatsQuerySummary: React.FC<StatsQuerySummaryProps> = ({
20	  detailed,
21	  numQueries,
22	  dataSources,
23	  lastRefresh,
24	  lastDuration,
25	  loading,
26	  warning
27	}) => {
28	  const { t } = useTranslation('plugin__netobserv-plugin');
29	
30	  const dateText = lastRefresh ? lastRefresh.toLocaleTimeString() : t('Loading...');
31	  const durationText = lastDuration ? formatDurationAboveMillisecond(lastDuration) : '';
32	
33	  const formatDatasources = React.useCallback(() => {
34	    return dataSources?.map(ds => (ds === 'prom' ? 'Prometheus' : ds === 'loki' ? 'Loki' : ds)).join(', ') || '';
35	  }, [dataSources]);
36	
37	  return (
38	    <FlexItem>
39	      <Tooltip
40	        content={
41	          <>
42	            <p>
43	              {lastRefresh
44	                ? t('Last refresh: {{time}}', {
45	                    time: dateText
46	                  })
47	                : dateText}
48	            </p>
49	            {dataSources?.length && <p>{t('Datasource(s): {{sources}}', { sources: formatDatasources() })}</p>}
50	            {numQueries && <p>{t('Query count: {{numQueries}}', { numQueries })}</p>}
51	            {durationText !== '' && <p>{t('Duration: {{duration}}', { duration: durationText })}</p>}
52	            {warning !== undefined && (
53	              <>
54	                <br />
55	                <p>{warning.summary}</p>
56	                <p>{warning.details}</p>
57	              </>
58	            )}
59	          </>
60	        }
61	      >
62	        <div className={`stats-query-summary-container-with-icon ${loading ? 'stats-loading-blink' : ''}`}>
63	          {warning !== undefined ? <ExclamationTriangleIcon /> : <GlobeAmericasIcon />}
64	          <Text id="lastRefresh" component={TextVariants.p}>
65	            {dateText}
66	            {detailed && numQueries && ` ${t('running')} ${numQueries} ${numQueries > 1 ? t('queries') : t('query')}`}
67	            {detailed && dataSources?.length && ` ${t('from')} ${formatDatasources()}`}
68	            {detailed && durationText !== '' && ` ${t('in')} ${durationText}`}
69	          </Text>
70	        </div>
71	      </Tooltip>
72	    </FlexItem>
73	  );
74	};
75	
76	export default StatsQuerySummary;

